// components/organisms/ProductList.tsx
import { ProductCard } from '../molecules/ProductCard';

function ProductList({ products }) {
  return (
    <section>
      {products.map(product => (
        <ProductCard key={product.id} product={product} />
      ))}
    </section>
  );
}

